where.trim:
and a.recycle=0
and a.recycle=b.recycle
and a.id = #{id}
and b.id = #{openId}
and a.store_id = #{store_id}
and u.user_name like concat('%', #{name},'%')
and team.user_name like concat('%', #{teamName},'%')
and c.product_title like concat('%', #{goodsName},'%')
and b.team_num = #{teamNum}
and b.status = #{status}
and ac.mch_id = #{mch_id}
and a.add_time   >=   #{startDate}
and a.add_time   <=   #{endDate}
and (c.product_title like concat('%', #{key},'%') or c.id = #{key})

mapper.select:
select a.id,a.goods_id,c.product_title,attr.attribute,a.price,a.attr_price,a.add_date,u.user_name,a.user_id,b.user_id mainUserId,team.user_name teamName,c.imgurl,b.status,b.team_num from lkt_group_open_record a inner join lkt_group_open b on a.open_id=b.id inner join lkt_product_list c on a.goods_id=c.id inner join lkt_configure attr on attr.id=a.attr_id inner join lkt_user u on u.user_id=a.user_id left join lkt_user team on team.user_id=b.user_id inner join lkt_group_activity ac on ac.id=b.activity_id
a.add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}

SELECT attr.id AS attrId,op.id AS openId,op.activity_id AS acId, op.`status`,o.id AS orderId, o.add_time, o.arrive_time settleDate,d.size,o.`status` AS orderStatus,mch.id mchId,mch.head_img mchImg, mch.`name` mchName, attr.img,d.p_name,attr.pid AS goodsId,d.p_id,op.team_num,o.z_price FROM lkt_order o LEFT JOIN lkt_order_details d ON d.r_sNo = o.sNo LEFT JOIN lkt_group_open_record re ON re.sno = o.sNo LEFT JOIN lkt_group_open op ON op.id = re.open_id LEFT JOIN lkt_configure attr ON attr.id = d.sid LEFT JOIN lkt_product_list c ON c.id = attr.pid LEFT JOIN lkt_mch mch ON mch.id = c.mch_id where o.recycle = 0 and o.user_id = #{userId}
#{sNo}
o.add_time ${add_date_sort},
limit #{pageStart},#{pageEnd}

mapper.sql:
and o.status >0

    and a.recycle = #{recycle} 
    and a.recycle = 0

and a.open_id = #{openId}
and o.status != #{notStatus}

mapper.select:
select o.id oid,o.sno,o.z_price,o.user_id,o.store_id,o.pay, o.mch_id, o.real_sno, o.status, b.num, b.id as detailId, c.id as attrId, c.pid from lkt_group_open_record a inner join lkt_order o on o.sno=a.sno inner join lkt_order_details b on b.r_sno=a.sno left join lkt_configure c on c.id = b.sid
a.add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}

SELECT count(1) FROM lkt_group_open_record re
LEFT JOIN lkt_group_open op ON op.id = re.open_id
where op.recycle = 0

    and op.status = #{status}


    and re.user_id = #{userId}

SELECT re.sno FROM lkt_group_open_record re
LEFT JOIN lkt_group_open op ON op.id = re.open_id
where op.recycle = 0

    and op.status = #{status}


    and re.user_id = #{userId}
